async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    await browser.navigateTo('https://www.instacart.com/');
    await browser.awaitPageLoad();

    const store = await browser.extractComponent<{ name: string; linkSelector?: string }>({
        typeName: 'StoreInfo',
        schema: '{ name: string; subtitle?: string; linkSelector?: string; }'
    }, params.storeName);
    if (store && store.linkSelector) {
        await browser.clickAndWait(store.linkSelector);
    }

    const buyAgainNav = await browser.extractComponent<{ linkSelector: string }>({
        typeName: 'BuyItAgainNavigationLink',
        schema: '{ linkSelector: string; }'
    });
    if (!buyAgainNav || !buyAgainNav.linkSelector) {
        throw new Error('Could not find Buy It Again section');
    }
    await browser.clickAndWait(buyAgainNav.linkSelector);

    const section = await browser.extractComponent<{ products?: { name: string; price: string; availability?: string; addToCartButtonSelector?: string }[] }>({
        typeName: 'BuyItAgainHeaderSection',
        schema: '{ allItemsSelector: string; pastOrdersSelector: string; products?: { name: string; price: string; availability?: string; addToCartButtonSelector?: string; }[]; }'
    });
    if (!section || !section.products || section.products.length === 0) {
        return { success: false, error: 'No past purchase items found' };
    }

    if (params.productName) {
        const match = section.products.find(
            p => p.name.toLowerCase().includes(params.productName.toLowerCase())
        );
        if (!match || !match.addToCartButtonSelector) {
            return { success: false, error: 'Could not find ' + params.productName + ' in past purchases' };
        }
        await browser.click(match.addToCartButtonSelector);
        await browser.awaitPageInteraction();
        return { success: true, message: 'Reordered ' + match.name + ' from Buy It Again' };
    }

    let added = 0;
    for (const product of section.products) {
        if (product.availability !== 'Out of stock' && product.addToCartButtonSelector) {
            await browser.click(product.addToCartButtonSelector);
            await browser.awaitPageInteraction();
            added++;
        }
    }
    return { success: true, message: 'Added ' + added + ' items from Buy It Again to cart' };
}
